// 行指定子 [i] = {...} と通常の行初期化子の混在が、ネスト指定子対応後も
// 従来どおり動くことを保証する回帰テスト。
// m[0]={1,2}, m[1]={0,0} (未指定で 0), m[2]={5,6}
// 期待: exit=44  (1+2+0+0+5+6 +30)
#include <assert.h>
int main(void) {
  int m[3][2] = { {1, 2}, [2] = {5, 6} };
  assert(m[0][0] == 1);
  assert(m[0][1] == 2);
  assert(m[1][0] == 0);   // 未指定 -> 0
  assert(m[1][1] == 0);
  assert(m[2][0] == 5);   // [2] = {5, 6}
  assert(m[2][1] == 6);
  return 0;
}
